INSERT INTO public.questions (id, exam_id, paper_id, subject_id, chapter_id, question_type, question_text, options, correct_answer, correct_answer_json, auto_gradable, source, is_active, version, source_meta, explanation)
VALUES
  ('elementary-64311456-moex-00455', 'elementary-64311456', 'elementary-64311456-moex-112-34c7f7f6', 'sub-elementary-64311456-02', NULL, 'single_choice', '「一切美好的事物都有美麗的開頭。不過，真正懂得人生的人都知道，『美好的開頭使事情 成功了一半』並不真。這個世界到處是美好的開頭，同時也到處是『只成功了一半』的事業。 美好的開頭不能結美好的果實。真正使事業成功，使一個人有成就的，是無窮的耐心。」 下列選項，何者最符合上文的旨趣？', '["懂得珍惜的人才會成功", "持之以恆才是成功的關鍵", "美好的果實，總是令人期待", "美好的開始，是成功的一半"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:09+00:00", "source_pdf_sha1": "956a0c9fbe15", "answer_pdf_sha1": "1a6f54ad7459", "source_family": "moex-gov-tw", "moex": {"exam_code": "112010", "c": "502", "s": "0101", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文", "year": "112", "exam_name": "112年公務人員初等考試", "original_question_number": 15, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "社會行政"}'::jsonb, NULL),
  ('elementary-64311456-moex-00456', 'elementary-64311456', 'elementary-64311456-moex-112-34c7f7f6', 'sub-elementary-64311456-02', NULL, 'single_choice', '「如果有人要你數算一個罐子裡的泡泡糖數量，你肯定可以輕鬆算出來，甚至還樂於嚐嚐罐 子裡不同口味的糖果。然而，如果要你站在一座裝滿泡泡糖的游泳池前，必須數出所有的糖 果數量，你大概連試都不想試了。」 下列選項，何者最有可能是「連試都不想試」的原因？', '["數大就是美", "小處做起建立信心", "根本不可能完成任務", "在任務中無法找到樂趣"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:09+00:00", "source_pdf_sha1": "956a0c9fbe15", "answer_pdf_sha1": "1a6f54ad7459", "source_family": "moex-gov-tw", "moex": {"exam_code": "112010", "c": "502", "s": "0101", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文", "year": "112", "exam_name": "112年公務人員初等考試", "original_question_number": 16, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "社會行政"}'::jsonb, NULL),
  ('elementary-64311456-moex-00457', 'elementary-64311456', 'elementary-64311456-moex-112-34c7f7f6', 'sub-elementary-64311456-02', NULL, 'single_choice', '「人類從存在以來就有刻板印象，在古代，生存和保護有賴家族和部落。同族的人是安全的， 陌生人是危險的。陌生人通常被當作敵人，只因為他們的外表、言語或行為不同而已。消除 刻板印象其實只需站在對方的立場，生活一週、一天或甚至一小時就行了。在職場上，行銷 部和生產部的人應該交換工作幾天，或至少做角色互換。主管和員工也應該交換工作幾天， 有一些聰明的公司就是這麼做。這減少了不信任和溝通的問題，增加團隊合作和生產力，最 主要的問題常在於，來自某文化的人從未接觸過另一文化的人。」 根據上文，下列選項何者最符合文意？', '["打從人類歷史以來便有根深柢固的成見，改變不易", "先入為主的觀念，不會阻絕溝通管道形成刻板印象", "職場上的角色互換可以啟發人的同理心，消弭歧見", "文化的隔閡，很少是不同族群產生衝突的重要因素"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:09+00:00", "source_pdf_sha1": "956a0c9fbe15", "answer_pdf_sha1": "1a6f54ad7459", "source_family": "moex-gov-tw", "moex": {"exam_code": "112010", "c": "502", "s": "0101", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文", "year": "112", "exam_name": "112年公務人員初等考試", "original_question_number": 17, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "社會行政"}'::jsonb, NULL),
  ('elementary-64311456-moex-00458', 'elementary-64311456', 'elementary-64311456-moex-112-34c7f7f6', 'sub-elementary-64311456-02', NULL, 'single_choice', '「簡單是一種修煉，越是面對複雜情境的人，這修煉越必要。但若修煉得宜，過程其實充滿 了喜悅，因為複雜的是人的頭腦和習性，人的本性和本心，始終都是簡單的。修煉簡單，就 是找回真我，重返赤子之心，豈有不樂之理？」 根據上文，下列選項何者最符合文意？', '["人們都是用心多，用腦少，往往自尋煩惱", "簡單的事，想太多就複雜，凡事不想就好", "複雜的事，看淡了就簡單，看透了就輕鬆", "保持赤子童心，並非一種尋回真我的修煉"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:09+00:00", "source_pdf_sha1": "956a0c9fbe15", "answer_pdf_sha1": "1a6f54ad7459", "source_family": "moex-gov-tw", "moex": {"exam_code": "112010", "c": "502", "s": "0101", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文", "year": "112", "exam_name": "112年公務人員初等考試", "original_question_number": 18, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "社會行政"}'::jsonb, NULL),
  ('elementary-64311456-moex-00459', 'elementary-64311456', 'elementary-64311456-moex-112-34c7f7f6', 'sub-elementary-64311456-02', NULL, 'single_choice', '「人們平常傾向於二分法的思考，例如：好與壞；英雄對惡棍；我的國家與其他國家。記者 擅長把相異的人事物寫成對立，偏好報導赤貧與富豪。紀錄片喜歡描寫無名小卒如何對抗邪 惡的大企業，賣座大片通常是在拍正義與邪惡的對立。由於二分法直覺，我們往往在統合中 想像對立，在融匯中想像歧異，在一致中想像衝突。這種直覺處處可見，徹底扭曲認知。所 以當你觀看兩個群體對立的新聞時，也許會用到『鴻溝越來越大』等用語。」 根據上文，下列選項最符合文意的是：', '["傳統善惡分明的教育中，人們判斷事物只剩下好與壞、對與錯的觀點", "媒體往往以直觀的方式在對立與歧異中尋求統合融匯，以增加收視率", "二分法的思考模式容易遭人利用，讓有心人士去強化衝突，製造爭端", "正邪不兩立的觀點，充斥在人們日常生活中，也是拍攝電影的好題材"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:09+00:00", "source_pdf_sha1": "956a0c9fbe15", "answer_pdf_sha1": "1a6f54ad7459", "source_family": "moex-gov-tw", "moex": {"exam_code": "112010", "c": "502", "s": "0101", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文", "year": "112", "exam_name": "112年公務人員初等考試", "original_question_number": 19, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "社會行政"}'::jsonb, NULL),
  ('elementary-64311456-moex-00460', 'elementary-64311456', 'elementary-64311456-moex-112-34c7f7f6', 'sub-elementary-64311456-02', NULL, 'single_choice', '承上題，下列選項何者最接近作者所說二分法思考的傾向？', '["革命尚未成功，同志仍需努力", "人不可以貌相，海水不可斗量", "過度捕撈造成許多海洋生物瀕臨絕種", "未開發國家的疫苗接種率普遍都偏低"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:09+00:00", "source_pdf_sha1": "956a0c9fbe15", "answer_pdf_sha1": "1a6f54ad7459", "source_family": "moex-gov-tw", "moex": {"exam_code": "112010", "c": "502", "s": "0101", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文", "year": "112", "exam_name": "112年公務人員初等考試", "original_question_number": 20, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "社會行政"}'::jsonb, NULL),
  ('elementary-64311456-moex-00461', 'elementary-64311456', 'elementary-64311456-moex-112-34c7f7f6', 'sub-elementary-64311456-02', NULL, 'single_choice', '「我寫小說的理由，追根究柢只有一個。就是讓個人靈魂的尊嚴浮上來，在那裡打上一道光。 為了不讓我們的靈魂被體制套牢、貶低，而經常照亮那裡，鳴響警鐘，那正是故事的任務。 我想藉著寫生與死的故事，寫愛的故事，繼續嘗試讓人哭泣，使人畏怯，引人發笑，每天認 真地繼續創作各種虛構的故事，讓每個靈魂不可替代的珍貴性明確化，這是小說家的工作。」 根據上文，作者對「小說家」的期許是：', '["在作品中，揭示所有靈魂相同而值得讚頌之處", "能凸顯出人性靈魂的尊嚴，並肯定其存在價值", "讓被體制套牢的角色可以鳴響警鐘，早日重生", "藉由虛構的故事使得讀者在哭笑後，洗滌情緒"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:09+00:00", "source_pdf_sha1": "956a0c9fbe15", "answer_pdf_sha1": "1a6f54ad7459", "source_family": "moex-gov-tw", "moex": {"exam_code": "112010", "c": "502", "s": "0101", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文", "year": "112", "exam_name": "112年公務人員初等考試", "original_question_number": 21, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "社會行政"}'::jsonb, NULL),
  ('elementary-64311456-moex-00462', 'elementary-64311456', 'elementary-64311456-moex-112-34c7f7f6', 'sub-elementary-64311456-02', NULL, 'single_choice', '以下是一個兒童繪本愛好者的自述：「繪本既是一個瑰麗的世界，也是一個隱藏著兒童角度 與文學內涵的世界。它不僅在形式特質上無可取代，就連它看世界的『眼神』，也不同於其 他的創作。我因為長年接觸繪本，從中發現了許多屬於兒童的特質，另外也因為它所傳遞出 來的是一些有別於成人世界的價值，而屢屢被書中的小孩顛覆。」 根據上文，下列選項何者最符合對兒童繪本的看法？', '["繪本所具有的形式特質較為瑰麗", "站在兒童的角度發現並了解世界", "以顛覆成人世界的價值觀為起點", "貼近小孩的文學內涵常無可取代"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:09+00:00", "source_pdf_sha1": "956a0c9fbe15", "answer_pdf_sha1": "1a6f54ad7459", "source_family": "moex-gov-tw", "moex": {"exam_code": "112010", "c": "502", "s": "0101", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文", "year": "112", "exam_name": "112年公務人員初等考試", "original_question_number": 22, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "社會行政"}'::jsonb, NULL),
  ('elementary-64311456-moex-00463', 'elementary-64311456', 'elementary-64311456-moex-112-34c7f7f6', 'sub-elementary-64311456-02', NULL, 'single_choice', '「萊爾德專門衝數層樓高的巨浪，每次出海，都像是與死神跳一首腳步繁複的雙人舞。他和 朋友曾經在衝浪時出過嚴重的事故，被巨浪重擊，同伴幾乎喪命在海上。萊爾德用盡力氣把 重傷的同伴拖回岸邊送上救護車後，第一件事竟是拿著浪板掉頭回到海裡，繼續衝浪。事後 有人問他難道不怕嗎？他說：不能害怕。」 根據上文，下列選項敘述正確的是：', '["萊爾德衝浪時，總能以技巧避開危險", "透過衝巨浪，萊爾德提升了衝浪技巧", "萊爾德不費吹灰之力救起溺水的同伴", "萊爾德征服恐懼的方法是直接面對它"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:09+00:00", "source_pdf_sha1": "956a0c9fbe15", "answer_pdf_sha1": "1a6f54ad7459", "source_family": "moex-gov-tw", "moex": {"exam_code": "112010", "c": "502", "s": "0101", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文", "year": "112", "exam_name": "112年公務人員初等考試", "original_question_number": 23, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "社會行政"}'::jsonb, NULL),
  ('elementary-64311456-moex-00464', 'elementary-64311456', 'elementary-64311456-moex-112-34c7f7f6', 'sub-elementary-64311456-02', NULL, 'single_choice', '「你如果順手撿起一塊花崗石的碎片，仔細看它的紋理，會發現含蓄而豐富的色彩，如果加 以放大，不輸一幅抽象畫。每顆石頭都有其獨特的紋理，並不是只有潔白光滑如凝脂的大理 石才是美的。」 下列選項，何者最能呼應上文意旨？', '["萬物自成其紋理，終究會被看見", "經過切磋琢磨，石頭方可展現美", "生活並不缺少美，只是缺少發現", "繁華落盡見真淳，平淡更有滋味"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:09+00:00", "source_pdf_sha1": "956a0c9fbe15", "answer_pdf_sha1": "1a6f54ad7459", "source_family": "moex-gov-tw", "moex": {"exam_code": "112010", "c": "502", "s": "0101", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文", "year": "112", "exam_name": "112年公務人員初等考試", "original_question_number": 24, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "社會行政"}'::jsonb, NULL)
